const Skybox: React.FC = () => {
  const meshRef = useRef<Mesh>(null);
  const starTextureUrl = useMemo(() => generateStarFieldTexture(), []);
  const starTexture = useMemo(() => {
    const t = new TextureLoader().load(starTextureUrl);
    t.wrapS = RepeatWrapping;
    t.wrapT = ClampToEdgeWrapping; 
    return t;
  }, [starTextureUrl]);

  useFrame((state, delta) => {
    if (meshRef.current) {
      meshRef.current.rotation.y += delta * 0.0001; // Slower background rotation
    }
  });

  return (
    <mesh ref={meshRef}>
      <sphereGeometry args={[500, 64, 64]} />
      <meshBasicMaterial 
        map={starTexture} 
        side={BackSide} 
        color="#ffffff"
      />
    </mesh>
  );
};

// Updated Controller with Smoothing to prevent Jitter
const OrbitController = ({ controlsRef, gestureVelocity }: { controlsRef: any, gestureVelocity: React.MutableRefObject<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}> }) => {
  // Store smoothed values to prevent camera shaking from noisy hand data
  const smoothed = useRef({ dx: 0, dy: 0 });

  useFrame((state, delta) => {
    if (controlsRef.current && controlsRef.current.enabled) {
      const { dx, dy, gestureType } = gestureVelocity.current;

      // Smoothing factor: Lower = Smoother/Slower, Higher = More responsive/Jittery
      const smoothFactor = 5.0 * delta;

      smoothed.current.dx = MathUtils.lerp(smoothed.current.dx, dx, smoothFactor);
      smoothed.current.dy = MathUtils.lerp(smoothed.current.dy, dy, smoothFactor);

      const threshold = 0.001; 
      const activeDx = Math.abs(smoothed.current.dx) > threshold ? smoothed.current.dx : 0;
      const activeDy = Math.abs(smoothed.current.dy) > threshold ? smoothed.current.dy : 0;

      const isActive = activeDx !== 0 || activeDy !== 0;

      if (isActive) {
          if (gestureType === 'rotate') {
             controlsRef.current.setAzimuthalAngle(controlsRef.current.getAzimuthalAngle() - activeDx * 0.02);
             controlsRef.current.setPolarAngle(controlsRef.current.getPolarAngle() - activeDy * 0.02);

          } else if (gestureType === 'zoom') {
             const zoomSensitivity = 0.015; 
             const speed = 1.0 + Math.abs(activeDy * zoomSensitivity);
             if (activeDy > 0) {
                 controlsRef.current.dollyIn(speed);
             } else {
                 controlsRef.current.dollyOut(speed);
             }
          }
          controlsRef.current.update();
      }
    }
  });
  return null;
}

const App: React.FC = () => {
  const [selectedPlanetId, setSelectedPlanetId] = useState<string | null>(null);
  const [isPaused, setIsPaused] = useState(false);
  const [simulationSpeed, setSimulationSpeed] = useState(1.0); 
  const [isStarshipActive, setIsStarshipActive] = useState(false);
  const [showPluto, setShowPluto] = useState(false);
  const [showOrbits, setShowOrbits] = useState(true);

  const [isGestureMode, setIsGestureMode] = useState(false);
  const [isARMode, setIsARMode] = useState(false);

  // Starship Controls State
  const [isBoostActive, setIsBoostActive] = useState(false);
  const [cameraModeIndex, setCameraModeIndex] = useState(0);
  const CAMERA_MODES = ['追尾', '驾驶舱', '无人机'];

  const earthPositionRef = useRef<Vector3>(new Vector3(0, 0, 0));
  const planetRefs = useRef<{ [key: string]: Object3D }>({});
  const controlsRef = useRef<any>(null);

  const gestureVelocity = useRef<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}>({ dx: 0, dy: 0, gestureType: 'rotate' });

  useEffect(() => {
    document.body.style.backgroundColor = isARMode ? 'transparent' : '#000';
    const root = document.getElementById('root');
    if (root) root.style.backgroundColor = isARMode ? 'transparent' : '#000';
  }, [isARMode]);

  const handleSelect = (id: string) => {
    setSelectedPlanetId(id);
    setIsPaused(true); 
  };

  const handleClose = () => {
    setSelectedPlanetId(null);
    setIsPaused(false); 
  };

  const togglePluto = () => {
    const newValue = !showPluto;
    setShowPluto(newValue);
    if (!newValue && selectedPlanetId === 'pluto') {
      handleClose();
    }
  };

  const toggleOrbits = () => {
    setShowOrbits(!showOrbits);
  };

  const handleGestureControl = (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => {
    gestureVelocity.current = { dx, dy, gestureType };
  };

  const toggleGestureMode = () => {
    const nextState = !isGestureMode;
    setIsGestureMode(nextState);
    if (nextState) {
      setSimulationSpeed(1.0);
    } else {
      setIsARMode(false);
    }
  };

  const handleToggleStarship = () => {
    const activating = !isStarshipActive;
    setIsStarshipActive(activating);
    if (activating) {
       setIsPaused(false);
       setSimulationSpeed(0.5); 
       // Reset controls
       setCameraModeIndex(0);
       setIsBoostActive(false);
    } else {
       setSimulationSpeed(1.0);
    }
  };

  const handleMissionComplete = () => {
     setIsStarshipActive(false);
     setSimulationSpeed(1.0); 
  };

  const selectedPlanet = useMemo(() => {
    if (selectedPlanetId === 'sun') return SUN_DATA;
    const planet = PLANETS.find(p => p.id === selectedPlanetId);
    if (planet) return planet;
    const jMoon = JUPITER_MOONS.find(m => m.id === selectedPlanetId);
    if (jMoon) return jMoon;
    return SATURN_MOONS.find(m => m.id === selectedPlanetId) || null;
  }, [selectedPlanetId]);

  const displayedPlanets = useMemo(() => {
    return showPluto ? PLANETS : PLANETS.filter(p => p.id !== 'pluto');
  }, [showPluto]);

  return (
    <div className="w-full h-screen relative overflow-hidden transition-colors duration-500"
         style={{ backgroundColor: isARMode ? 'transparent' : '#000' }}
    >

      <UIOverlay 
        selectedPlanet={selectedPlanet}
        onClose={handleClose}
        isPaused={isPaused}
        togglePause={() => setIsPaused(!isPaused)}
        simulationSpeed={simulationSpeed}
        setSimulationSpeed={setSimulationSpeed}
        isStarshipActive={isStarshipActive}
        toggleStarship={handleToggleStarship}
        showPluto={showPluto}
        togglePluto={togglePluto}
        isGestureMode={isGestureMode}
        toggleGestureMode={toggleGestureMode}
        showOrbits={showOrbits}
        toggleOrbits={toggleOrbits}
        // Pass flight controls
        onBoost={setIsBoostActive}
        onToggleCamera={() => setCameraModeIndex(prev => (prev + 1) % 3)}
        cameraModeLabel={CAMERA_MODES[cameraModeIndex]}
      />

      {isGestureMode && (
        <GestureController 
          onControl={handleGestureControl} 
          onClose={() => toggleGestureMode()} 
          isARMode={isARMode}
          toggleARMode={() => setIsARMode(!isARMode)}
        />
      )}

      <Canvas 
        gl={{ antialias: true, toneMappingExposure: 1.2, alpha: true }}
        onPointerMissed={() => {
          if (selectedPlanetId) handleClose();
        }}
      >
        <Suspense fallback={null}>
          <PerspectiveCamera makeDefault position={[0, 80, 120]} fov={45} />

          <OrbitControls 
            ref={controlsRef}
            makeDefault
            enabled={!isStarshipActive} 
            enableDamping={true}
            dampingFactor={0.05}
            enablePan={false}
            minDistance={20}
            maxDistance={300}
            maxPolarAngle={Math.PI / 1.8}
            autoRotate={!selectedPlanetId && !isPaused && !isGestureMode && !isStarshipActive}
            autoRotateSpeed={0.1 * simulationSpeed} 
          />

          <OrbitController controlsRef={controlsRef} gestureVelocity={gestureVelocity} />

          <Environment preset="city" environmentIntensity={0.3} />
          <pointLight position={[0, 0, 0]} intensity={2.5} distance={500} decay={1} color="#FFF5E0" />
          <ambientLight intensity={0.15} color="#404060" />

          {/* Stars are always visible */}
          <Stars radius={400} depth={50} count={3000} factor={4} saturation={0.5} fade speed={0.5} />

          {/* Hide skybox in AR or when Starship warping (Starship creates its own warp tunnel visual) */}
          {!isARMode && <Skybox />}

          <Sparkles count={400} scale={200} size={6} speed={0.2} opacity={0.4} noise={0.1} color="#88AAFF" />
          <Sparkles count={150} scale={150} size={3} speed={0.3} opacity={0.6} color="#FFD700" />

          <Sun 
             onSelect={handleSelect}
             isSelected={selectedPlanetId === 'sun'}
             isPaused={isPaused}
             simulationSpeed={simulationSpeed}
          />

          <AsteroidBelt isPaused={isPaused} simulationSpeed={simulationSpeed} />

          {displayedPlanets.map((planet) => (
            <Planet 
              key={planet.id} 
              data={planet} 
              isSelected={selectedPlanetId === planet.id}
              onSelect={handleSelect}
              isPaused={isPaused}
              simulationSpeed={simulationSpeed}
              earthPositionRef={earthPositionRef}
              planetRefs={planetRefs}
              isStarshipActive={isStarshipActive}
              showOrbit={showOrbits}
            />
          ))}

          {isStarshipActive && (
             <Starship 
                planetRefs={planetRefs} 
                onMissionComplete={handleMissionComplete}
                isBoostActive={isBoostActive}
                cameraMode={cameraModeIndex}
             />
          )}

        </Suspense>
      </Canvas>
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { Vector3, Group, Object3D, AdditiveBlending, Quaternion, MathUtils, Euler } from 'three';
import { Trail, Html, Text, Sparkles } from '@react-three/drei';
import { PLANETS } from '../constants';

interface StarshipProps {
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
  onMissionComplete: () => void;
  isBoostActive: boolean;
  cameraMode: number; // 0: TPS, 1: Cockpit, 2: Drone
}

type ShipState = 'IDLE' | 'ALIGNING' | 'WARP' | 'APPROACH' | 'ORBITING';

// --- VISUAL EFFECTS: Warp Tunnel Particles ---
const WarpParticles: React.FC<{ active: boolean; boost: boolean }> = ({ active, boost }) => {
  if (!active) return null;
  return (
    <group rotation={[0, 0, 0]}>
       {/* High speed streaks when boosting */}
       <Sparkles 
         count={boost ? 300 : 100} 
         scale={[10, 10, 40]} // Long tunnel shape
         size={boost ? 12 : 6} 
         speed={boost ? 5 : 2} 
         opacity={boost ? 0.8 : 0.4} 
         color={boost ? "#00ffff" : "#ffffff"}
         noise={0.1}
       />
    </group>
  );
};

export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete, isBoostActive, cameraMode }) => {
  const groupRef = useRef<Group>(null);
  const shipModelRef = useRef<Group>(null);
  const particlesRef = useRef<Group>(null);

  // Logic State
  const [currentSpeedDisplay, setCurrentSpeedDisplay] = useState(0);
  const [statusText, setStatusText] = useState("系统启动中...");

  // State Machine Refs
  const stateRef = useRef<ShipState>('IDLE');
  const missionQueueRef = useRef<string[]>([]);
  const currentTargetIdRef = useRef<string | null>(null);

  // Physics Refs
  const currentSpeedRef = useRef(0);
  const velocityRef = useRef(new Vector3());
  const orbitTimeRef = useRef(0);

  // Camera State
  const camPosRef = useRef(new Vector3(0, 20, 40));
  const camLookRef = useRef(new Vector3());

  // Constants
  const BASE_SPEED = 25;
  const BOOST_SPEED = 80;
  const ROT_SPEED = 3.0;

  // --- MISSION PLANNER ---
  const generateMission = () => {
     // Create a fun route: Earth -> Random -> Random -> Random -> Earth
     const candidates = PLANETS.filter(p => p.id !== 'mercury' && p.id !== 'earth').map(p => p.id);
     const mission: string[] = [];

     // Pick 3 random destinations
     for (let i = 0; i < 3; i++) {
        const next = candidates[Math.floor(Math.random() * candidates.length)];
        mission.push(next);
     }
     mission.push('earth'); // Return home
     return mission;
  };

  useFrame((state, delta) => {
    if (!groupRef.current) return;
    const shipPos = groupRef.current.position;

    // --- 1. INITIALIZATION ---
    if (stateRef.current === 'IDLE') {
       const earthObj = planetRefs.current['earth'];
       if (earthObj) {
           const startPos = new Vector3();
           earthObj.getWorldPosition(startPos);
           if (startPos.lengthSq() > 1) {
              groupRef.current.position.copy(startPos).add(new Vector3(0, 10, 10)); // Start near Earth
              groupRef.current.lookAt(new Vector3(0,0,0));
              missionQueueRef.current = generateMission();
              stateRef.current = 'ALIGNING';
           }
       }
       return;
    }

    // --- 2. TARGET LOGIC ---
    let targetPos = new Vector3();
    let targetRadius = 20;

    // Check if we have a valid target
    if ((stateRef.current === 'ALIGNING' || stateRef.current === 'WARP' || stateRef.current === 'APPROACH') && !currentTargetIdRef.current) {
        if (missionQueueRef.current.length > 0) {
            const nextId = missionQueueRef.current.shift()!;
            currentTargetIdRef.current = nextId;
            const pName = PLANETS.find(p => p.id === nextId)?.name || nextId;
            setStatusText(`目标锁定: ${pName.split(' ')[0]}`);
        } else {
            onMissionComplete();
            return;
        }
    }

    // Get Target World Position
    if (currentTargetIdRef.current && planetRefs.current[currentTargetIdRef.current]) {
        planetRefs.current[currentTargetIdRef.current].getWorldPosition(targetPos);
        const pData = PLANETS.find(p => p.id === currentTargetIdRef.current);
        if (pData) targetRadius = pData.size * 3 + 12; // Dynamic orbit distance
    }

    const distToTarget = shipPos.distanceTo(targetPos);

    // --- 3. STATE UPDATE & MOVEMENT ---

    // STATE: ALIGNING (Turn to face target)
    if (stateRef.current === 'ALIGNING') {
        const dirToTarget = targetPos.clone().sub(shipPos).normalize();
        const targetQuat = new Quaternion().setFromUnitVectors(new Vector3(0,0,1), dirToTarget);
        groupRef.current.quaternion.slerp(targetQuat, delta * 2.0);

        // Move slightly
        groupRef.current.translateZ(10 * delta);

        if (groupRef.current.quaternion.angleTo(targetQuat) < 0.1) {
            stateRef.current = 'WARP';
            setStatusText("引擎全开！(按住 🔥 加速)");
        }
    }

    // STATE: WARP (Fly to target)
    if (stateRef.current === 'WARP') {
        const dirToTarget = targetPos.clone().sub(shipPos).normalize();

        // Speed logic
        const targetSpeed = isBoostActive ? BOOST_SPEED : BASE_SPEED;
        currentSpeedRef.current = MathUtils.lerp(currentSpeedRef.current, targetSpeed, delta * 2);

        // Move
        groupRef.current.position.add(dirToTarget.multiplyScalar(currentSpeedRef.current * delta));
        groupRef.current.lookAt(targetPos); // Keep focused

        // Roll effect when boosting
        if (shipModelRef.current) {
            const roll = isBoostActive ? Math.sin(state.clock.elapsedTime * 10) * 0.1 : 0;
            shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, roll, delta * 5);
        }

        // Transition to Approach
        if (distToTarget < targetRadius + 30) {
            stateRef.current = 'APPROACH';
            setStatusText("正在减速入轨...");
        }
    }

    // STATE: APPROACH (Slow down and bank into orbit)
    if (stateRef.current === 'APPROACH') {
        currentSpeedRef.current = MathUtils.lerp(currentSpeedRef.current, 10, delta * 3);

        // Curve path towards a tangent point of the orbit
        const dirToTarget = targetPos.clone().sub(shipPos).normalize();
        groupRef.current.position.add(dirToTarget.multiplyScalar(currentSpeedRef.current * delta));

        // Smoothly look at target
        const dummy = new Object3D();
        dummy.position.copy(shipPos);
        dummy.lookAt(targetPos);
        groupRef.current.quaternion.slerp(dummy.quaternion, delta * 5);

        if (distToTarget < targetRadius + 2) {
             stateRef.current = 'ORBITING';
             orbitTimeRef.current = 0;
             setStatusText("环绕航行中...");
        }
    }

    // STATE: ORBITING (Circle target)
    if (stateRef.current === 'ORBITING') {
        currentSpeedRef.current = MathUtils.lerp(currentSpeedRef.current, 8, delta);
        orbitTimeRef.current += delta * 0.5; // Orbit speed

        // Calculate orbit position (Circle in XZ plane relative to planet)
        // We calculate position based on angle to ensure smooth circle
        const angle = orbitTimeRef.current; 
        const offsetX = Math.cos(angle) * targetRadius;
        const offsetZ = Math.sin(angle) * targetRadius;

        // We need to maintain the planet's world position as center
        const nextPos = new Vector3(targetPos.x + offsetX, targetPos.y, targetPos.z + offsetZ);

        // Lerp to orbit track to avoid snapping
        groupRef.current.position.lerp(nextPos, delta * 2);

        // Banking: Look along tangent
        const futureAngle = angle + 0.5;
        const lookX = targetPos.x + Math.cos(futureAngle) * targetRadius;
        const lookZ = targetPos.z + Math.sin(futureAngle) * targetRadius;
        const lookAtPos = new Vector3(lookX, targetPos.y, lookZ);

        const dummy = new Object3D();
        dummy.position.copy(shipPos);
        dummy.lookAt(lookAtPos);
        groupRef.current.quaternion.slerp(dummy.quaternion, delta * 2);

        // Bank the ship model inward
        if (shipModelRef.current) {
             shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, -Math.PI / 4, delta * 2);
        }

        // Leave after a partial orbit (e.g., 3/4 circle) or time
        if (orbitTimeRef.current > 4.5) { 
            stateRef.current = 'ALIGNING';
            currentTargetIdRef.current = null; // Clear target to pick next

            // Reset Bank
             if (shipModelRef.current) {
                 shipModelRef.current.rotation.z = 0;
             }
        }
    }

    // --- 4. CAMERA SYSTEM ---
    const shipQuat = groupRef.current.quaternion;
    const forward = new Vector3(0, 0, 1).applyQuaternion(shipQuat);
    const up = new Vector3(0, 1, 0).applyQuaternion(shipQuat);

    let targetCamPos = new Vector3();
    let targetLookAt = new Vector3();
    let fov = 45;

    // Shake effect
    const shake = isBoostActive ? (Math.random() - 0.5) * 0.2 : 0;

    if (cameraMode === 0) {
        // TPS (Third Person) - Behind and above
        const dist = isBoostActive ? 25 : 18;
        const height = 8;
        const offset = forward.clone().multiplyScalar(-dist).add(up.clone().multiplyScalar(height));
        targetCamPos.copy(shipPos).add(offset);
        targetLookAt.copy(shipPos).add(forward.clone().multiplyScalar(20)); // Look ahead
        if (isBoostActive) fov = 65; // Speed effect
    } 
    else if (cameraMode === 1) {
        // COCKPIT (First Person) - Inside nose
        const offset = forward.clone().multiplyScalar(1.2).add(up.clone().multiplyScalar(0.2));
        targetCamPos.copy(shipPos).add(offset);
        targetLookAt.copy(shipPos).add(forward.clone().multiplyScalar(50));
        if (isBoostActive) fov = 80; // Intense warp effect
    }
    else if (cameraMode === 2) {
        // DRONE (Cinematic) - Rotates around ship
        const angle = state.clock.elapsedTime * 0.5;
        const dist = 25;
        const droneOffset = new Vector3(Math.cos(angle) * dist, 5, Math.sin(angle) * dist);
        targetCamPos.copy(shipPos).add(droneOffset);
        targetLookAt.copy(shipPos);
    }

    // Apply Shake
    targetCamPos.addScalar(shake);

    // Lerp Camera
    state.camera.position.lerp(targetCamPos, delta * 3);

    // Smooth LookAt (manual slerp for quaternion or lerp for vector lookat usually works ok with OrbitControls disabled)
    // We update the camera logic manually here.
    // Create a dummy object to calculate rotation
    const dummyCam = new Object3D();
    dummyCam.position.copy(state.camera.position);
    dummyCam.lookAt(targetLookAt);
    state.camera.quaternion.slerp(dummyCam.quaternion, delta * 4);

    state.camera.fov = MathUtils.lerp(state.camera.fov, fov, delta * 2);
    state.camera.updateProjectionMatrix();

    // --- 5. EFFECTS UPDATES ---
    // Move Particles to camera so they always surround the player
    if (particlesRef.current) {
        const offsetAhead = forward.clone().multiplyScalar(20); // Put tunnel ahead of ship
        particlesRef.current.position.copy(shipPos).add(offsetAhead); 
        particlesRef.current.quaternion.copy(shipQuat);
    }

    // Update Speed Display
    const displayVal = Math.round(currentSpeedRef.current * 100);
    if (Math.abs(displayVal - currentSpeedDisplay) > 50) setCurrentSpeedDisplay(displayVal);

  });

  return (
    <>
      <group ref={groupRef} scale={[1.8, 1.8, 1.8]}>
         {/* Particles follow the ship group logic manually in useFrame, but let's parent them here for simpler cleanup if needed, 
             actually better to keep outside if we want world space trails, but inside is fine for local Warp Tunnel */}
         <group ref={particlesRef}>
            <WarpParticles active={stateRef.current === 'WARP'} boost={isBoostActive} />
         </group>

         {/* HUD Label */}
         <Html position={[0, 2, 0]} center sprite zIndexRange={[100, 0]}>
             <div className="flex flex-col items-center pointer-events-none select-none">
                <div className="bg-cyan-900/60 border border-cyan-400 backdrop-blur-md px-4 py-2 rounded-xl text-center transform shadow-[0_0_20px_rgba(6,182,212,0.6)]">
                    <div className="text-[10px] text-cyan-200 uppercase tracking-widest mb-1">Status</div>
                    <div className="text-lg font-bold text-white whitespace-nowrap">{statusText}</div>
                    <div className="h-1 w-full bg-gray-700 mt-2 rounded-full overflow-hidden">
                        <div className="h-full bg-cyan-400 transition-all duration-300" 
                             style={{ width: `${Math.min((currentSpeedDisplay / (BOOST_SPEED*100))*100, 100)}%` }}></div>
                    </div>
                </div>
                <div className="mt-1 text-cyan-300 font-mono text-xs font-bold">{currentSpeedDisplay} KM/H</div>
             </div>
         </Html>

         <group ref={shipModelRef}>
            {/* Rotate geometry to match Z-forward */}
            <group rotation={[Math.PI / 2, 0, 0]}>

                {/* 1. Main Hull */}
                <mesh position={[0, 0, 0]}>
                  <cylinderGeometry args={[0.35, 0.35, 1.6, 32]} />
                  <meshPhysicalMaterial color="#e2e8f0" metalness={0.9} roughness={0.2} clearcoat={1.0} />
                </mesh>

                {/* Glowing Name */}
                <group position={[0, 0, 0.36]}>
                     <Text color="white" fontSize={0.28} anchorX="center" anchorY="middle" outlineWidth={0.02} outlineColor="#00FFFF">
                       {'小\n豆\n子\n号'}
                     </Text>
                </group>

                {/* 2. Nose Cone */}
                <mesh position={[0, 1.15, 0]}>
                  <coneGeometry args={[0.35, 0.7, 32]} />
                  <meshPhysicalMaterial color="#e2e8f0" metalness={0.9} roughness={0.2} clearcoat={1.0} />
                </mesh>

                {/* 3. Wings/Flaps */}
                <group position={[0, -0.6, 0]}>
                   <mesh position={[-0.45, 0, 0]} rotation={[0, 0, 0.1]}>
                      <boxGeometry args={[0.3, 0.6, 0.08]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
                   </mesh>
                   <mesh position={[0.45, 0, 0]} rotation={[0, 0, -0.1]}>
                      <boxGeometry args={[0.3, 0.6, 0.08]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
                   </mesh>
                </group>

                {/* 4. Engines & Flame */}
                <group position={[0, -0.85, 0]}>
                   <mesh><cylinderGeometry args={[0.25, 0.2, 0.1, 16]} /><meshStandardMaterial color="#111" /></mesh>
                </group>

                {/* Dynamic Engine Flame - Scales with Boost */}
                <group position={[0, -0.9, 0]} scale={[1, isBoostActive ? 2.5 : 1.0, 1]}>
                    <mesh position={[0, -0.7, 0]}>
                      <cylinderGeometry args={[0.15, 0.0, 1.4, 16, 1, true]} /> 
                      <meshBasicMaterial color={isBoostActive ? "#FF0000" : "#8B5CF6"} transparent opacity={0.6} blending={AdditiveBlending} depthWrite={false} />
                    </mesh>
                    <mesh position={[0, -0.5, 0]}>
                      <cylinderGeometry args={[0.1, 0.0, 1.0, 16, 1, true]} /> 
                      <meshBasicMaterial color="#06b6d4" transparent opacity={0.8} blending={AdditiveBlending} depthWrite={false} />
                    </mesh>
                </group>

                <pointLight position={[0, -1, 0]} color="#06b6d4" distance={5} intensity={isBoostActive ? 8 : 4} />
            </group>

            {/* Trail always active but longer when fast */}
            <group position={[0, 0, -1.2]}>
              <Trail width={isBoostActive ? 0.8 : 0.4} length={isBoostActive ? 12 : 6} color={isBoostActive ? "#00FFFF" : "#06b6d4"} attenuation={(t) => t * t}>
                <mesh visible={false}><boxGeometry args={[0.1, 0.1, 0.1]} /></mesh>
              </Trail>
            </group>
         </group>
      </group>
    </>
  );
};

import React, { useRef, useState, useEffect, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { Vector3, Group, Object3D, Quaternion, MathUtils, Matrix4 } from 'three';
import { Trail, Html, Text, Sparkles } from '@react-three/drei';
import { PLANETS } from '../constants';

interface StarshipProps {
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
  onMissionComplete: () => void;
  isBoostActive: boolean;
  cameraMode: number; // 0: TPS (Chase), 1: Cockpit, 2: Drone (Cinematic)
}

// Visual: Speed lines that appear when flying fast
const WarpTunnel: React.FC<{ speed: number }> = ({ speed }) => {
  const count = 200;
  // Dynamic scale based on speed: Higher speed = longer lines
  const length = MathUtils.clamp(speed * 0.5, 5, 50);
  const opacity = MathUtils.clamp((speed - 20) / 60, 0, 0.8);

  if (speed < 10) return null;

  return (
    <group>
       <Sparkles 
         count={count} 
         scale={[40, 40, 100]} // Long tunnel
         size={length} 
         speed={speed * 0.1} 
         opacity={opacity}
         color="#b3e5fc"
         noise={0.5}
       />
    </group>
  );
};

export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete, isBoostActive, cameraMode }) => {
  const shipRef = useRef<Group>(null);
  const modelRef = useRef<Group>(null);
  const engineGlowRef = useRef<Group>(null);

  // Logic State
  const [targetId, setTargetId] = useState<string | null>(null);
  const [status, setStatus] = useState("准备启航");

  // Physics Refs (Mutable for performance)
  const position = useRef(new Vector3(0, 20, 40)); // Start near camera
  const velocity = useRef(new Vector3(0, 0, 0));
  const speedRef = useRef(0);
  const targetOrbitAngle = useRef(0);
  const missionQueue = useRef<string[]>([]);

  // Camera Lag Refs
  const cameraPosLag = useRef(new Vector3(0, 50, 80));
  const cameraLookLag = useRef(new Vector3(0, 0, 0));

  // Constants
  const MIN_SPEED = 20;
  const MAX_SPEED = 120; // Boost speed
  const ACCELERATION = 40;
  const TURN_SPEED = 3.0;
  const ORBIT_DISTANCE_MULTIPLIER = 2.5; // Orbit radius relative to planet size

  // --- MISSION PLANNER ---
  useEffect(() => {
    // Generate a random tour path
    const planetIds = PLANETS.map(p => p.id).filter(id => id !== 'sun'); // Don't fly into the sun
    // Shuffle
    for (let i = planetIds.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [planetIds[i], planetIds[j]] = [planetIds[j], planetIds[i]];
    }
    // Ensure we start by going to Earth if not there, or just pick first 3
    missionQueue.current = planetIds.slice(0, 4);

    // Initial Spawn Position (Near Earth if possible)
    if (planetRefs.current['earth']) {
        const earthPos = new Vector3();
        planetRefs.current['earth'].getWorldPosition(earthPos);
        position.current.copy(earthPos).add(new Vector3(0, 10, 20));
    }
  }, []);

  useFrame((state, delta) => {
    if (!shipRef.current) return;

    // 1. TARGET ACQUISITION
    if (!targetId) {
        if (missionQueue.current.length > 0) {
            const next = missionQueue.current.shift()!;
            setTargetId(next);
            const pName = PLANETS.find(p => p.id === next)?.name.split(' ')[0];
            setStatus(`前往: ${pName}`);
        } else {
            // Mission Loop: Replenish queue
             const planetIds = PLANETS.map(p => p.id).filter(id => id !== 'sun');
             missionQueue.current = planetIds.slice(0, 3);
        }
        return;
    }

    const targetObj = planetRefs.current[targetId];
    if (!targetObj) return; // Wait for planet to mount

    const targetPos = new Vector3();
    targetObj.getWorldPosition(targetPos);

    // Determine dynamic orbit radius based on planet size
    const pData = PLANETS.find(p => p.id === targetId);
    const planetSize = pData ? pData.size : 2;
    const orbitRadius = planetSize * ORBIT_DISTANCE_MULTIPLIER + 8;

    const distToTarget = position.current.distanceTo(targetPos);
    const dirToTarget = targetPos.clone().sub(position.current).normalize();

    // 2. FLIGHT LOGIC (State Machine inside Physics)

    // Target Speed Calculation
    let targetSpeedVal = MIN_SPEED;
    let turnRate = TURN_SPEED;

    const isOrbiting = distToTarget < orbitRadius + 5;

    if (isOrbiting) {
        // --- ORBIT MODE ---
        setStatus("环绕观测中...");
        targetSpeedVal = 15; // Slow down for orbit

        // Calculate tangent vector for orbit (Simple circular logic)
        // We want to move perpendicular to the radius vector
        targetOrbitAngle.current += delta * 0.5; // Orbit speed

        // Desired position in orbit
        const desiredX = targetPos.x + Math.cos(targetOrbitAngle.current) * orbitRadius;
        const desiredZ = targetPos.z + Math.sin(targetOrbitAngle.current) * orbitRadius;
        const desiredPos = new Vector3(desiredX, targetPos.y, desiredZ);

        // Move towards desired orbit point
        const dirToOrbit = desiredPos.sub(position.current).normalize();

        // Smoothly blend velocity
        velocity.current.lerp(dirToOrbit.multiplyScalar(targetSpeedVal), delta * 2.0);

        // Leave orbit condition
        if (targetOrbitAngle.current > Math.PI * 1.5) { // Do about 3/4 of an orbit
            setTargetId(null); // Pick next target
            targetOrbitAngle.current = 0;
        }

    } else {
        // --- TRANSIT MODE ---
        // Boost logic
        targetSpeedVal = isBoostActive ? MAX_SPEED : MIN_SPEED;

        // Arrival slowing
        if (distToTarget < orbitRadius + 50) {
            targetSpeedVal = MathUtils.lerp(targetSpeedVal, 20, 0.1);
            setStatus("减速入轨...");
        } else if (isBoostActive) {
            setStatus("超光速推进!");
        }

        // Steer towards target
        velocity.current.lerp(dirToTarget.multiplyScalar(targetSpeedVal), delta * (isBoostActive ? 0.5 : 1.5));
    }

    // Apply Velocity
    speedRef.current = MathUtils.lerp(speedRef.current, velocity.current.length(), delta * 2);
    position.current.add(velocity.current.clone().multiplyScalar(delta));

    // Update Ship Position
    shipRef.current.position.copy(position.current);

    // Rotation (Look forward)
    const lookTarget = position.current.clone().add(velocity.current);
    const dummy = new Object3D();
    dummy.position.copy(position.current);
    dummy.lookAt(lookTarget);
    shipRef.current.quaternion.slerp(dummy.quaternion, delta * 4.0);

    // Banking (Roll) when turning
    if (modelRef.current) {
        // Calculate turn intensity (y-axis rotation delta approx)
        const rollAmount = -velocity.current.x * 0.02; // Simple approximation
        // Add wiggle on boost
        const shake = isBoostActive ? Math.sin(state.clock.elapsedTime * 30) * 0.1 : 0;

        // Smooth roll
        modelRef.current.rotation.z = MathUtils.lerp(modelRef.current.rotation.z, rollAmount + shake, delta * 3);
    }

    // Engine Glow Scale
    if (engineGlowRef.current) {
        const scale = MathUtils.lerp(1, isBoostActive ? 4 : 1.5, delta * 5);
        engineGlowRef.current.scale.set(scale, scale, scale * 2); // Stretch Z more
    }


    // 3. CAMERA SYSTEM (The Cinematic Director)

    // Calculate Ideal Camera Position & LookAt based on mode
    const shipPos = position.current;
    const shipQuat = shipRef.current.quaternion;
    const back = new Vector3(0, 0, -1).applyQuaternion(shipQuat).negate(); // Forward actually
    const up = new Vector3(0, 1, 0).applyQuaternion(shipQuat);

    let idealOffset = new Vector3();
    let idealLook = new Vector3();
    let targetFov = 45;

    if (cameraMode === 0) {
        // TPS (Chase)
        // Distance increases with speed
        const camDist = 20 + (speedRef.current / MAX_SPEED) * 20; 
        idealOffset = back.clone().multiplyScalar(-camDist).add(up.clone().multiplyScalar(8));
        idealLook = shipPos.clone().add(back.clone().multiplyScalar(50)); // Look ahead of ship
        targetFov = 50 + (speedRef.current / MAX_SPEED) * 30; // Speed FOV
    } else if (cameraMode === 1) {
        // Cockpit
        idealOffset = back.clone().multiplyScalar(1.5).add(up.clone().multiplyScalar(0.5));
        idealLook = shipPos.clone().add(back.clone().multiplyScalar(100));
        targetFov = 70 + (speedRef.current / MAX_SPEED) * 40; // Wider FOV sensation
    } else {
        // Drone (Cinematic Orbit around ship)
        const time = state.clock.elapsedTime * 0.5;
        const radius = 30;
        idealOffset = new Vector3(Math.cos(time) * radius, 10, Math.sin(time) * radius);
        // Transform local rotation to world relative to ship? No, drone is world space usually
        // Let's make drone relative to ship but rotating
        idealOffset.applyQuaternion(shipQuat); 
        idealLook = shipPos.clone();
        targetFov = 40;
    }

    // Camera Physics (Lag)
    // Lerp factor: Low = heavy lag (cinematic), High = tight control
    const lerpFactor = cameraMode === 1 ? 0.5 : 0.1; 

    // We calculate world position for ideal camera
    const desiredCamPos = shipPos.clone().add(idealOffset);

    // Smoothly interpolate current camera lag var to desired
    cameraPosLag.current.lerp(desiredCamPos, delta * (cameraMode === 1 ? 20 : 3));
    cameraLookLag.current.lerp(idealLook, delta * (cameraMode === 1 ? 20 : 4));

    // Apply Shake to Camera
    const camShake = isBoostActive ? new Vector3(
        (Math.random() - 0.5) * 0.5,
        (Math.random() - 0.5) * 0.5, 
        (Math.random() - 0.5) * 0.5
    ) : new Vector3();

    // Update Actual Camera
    state.camera.position.copy(cameraPosLag.current).add(camShake);
    state.camera.lookAt(cameraLookLag.current);
    state.camera.fov = MathUtils.lerp(state.camera.fov, targetFov, delta * 2);
    state.camera.updateProjectionMatrix();

  });

  return (
    <group ref={shipRef} scale={[1.5, 1.5, 1.5]}>

      {/* Visuals attached to ship */}
      <WarpTunnel speed={speedRef.current} />

      {/* HUD Info floating above ship */}
      <Html position={[0, 3, 0]} center zIndexRange={[100, 0]}>
         <div className="flex flex-col items-center pointer-events-none select-none opacity-80">
            <div className="text-xs text-cyan-300 font-mono mb-1 tracking-widest uppercase bg-black/50 px-2 rounded">
               {status}
            </div>
            <div className="w-24 h-1 bg-gray-700 rounded-full overflow-hidden border border-gray-600">
               <div 
                 className="h-full bg-gradient-to-r from-cyan-400 to-white transition-all duration-75"
                 style={{ width: `${(speedRef.current / MAX_SPEED) * 100}%` }}
               />
            </div>
            <div className="text-[10px] text-white mt-1 font-bold">
               {Math.round(speedRef.current * 10)} KM/H
            </div>
         </div>
      </Html>

      {/* Ship Model - Rotates for banking */}
      <group ref={modelRef}>
         {/* --- 3D GEOMETRY OF THE SHIP --- */}

         {/* Body */}
         <mesh rotation={[Math.PI / 2, 0, 0]}>
            <cylinderGeometry args={[0.4, 0.6, 3, 6]} />
            <meshStandardMaterial color="#cbd5e1" roughness={0.3} metalness={0.8} />
         </mesh>

         {/* Cockpit */}
         <mesh position={[0, 0.5, 0.5]}>
            <boxGeometry args={[0.6, 0.5, 1.2]} />
            <meshStandardMaterial color="#334155" roughness={0.2} metalness={0.5} />
         </mesh>
         <mesh position={[0, 0.6, 0.8]}>
             <boxGeometry args={[0.5, 0.05, 0.8]} />
             <meshStandardMaterial color="#0ea5e9" emissive="#0ea5e9" emissiveIntensity={0.5} toneMapped={false} />
         </mesh>

         {/* Wings */}
         <group position={[0, 0, -0.5]}>
            <mesh position={[1.2, 0, 0]} rotation={[0, 0, -0.2]}>
               <boxGeometry args={[2, 0.1, 1]} />
               <meshStandardMaterial color="#475569" roughness={0.5} metalness={0.6} />
            </mesh>
            <mesh position={[-1.2, 0, 0]} rotation={[0, 0, 0.2]}>
               <boxGeometry args={[2, 0.1, 1]} />
               <meshStandardMaterial color="#475569" roughness={0.5} metalness={0.6} />
            </mesh>
            {/* Wing Tips Lights */}
            <mesh position={[2.1, 0, 0.4]}>
               <sphereGeometry args={[0.1]} />
               <meshBasicMaterial color="#ef4444" />
            </mesh>
            <mesh position={[-2.1, 0, 0.4]}>
               <sphereGeometry args={[0.1]} />
               <meshBasicMaterial color="#22c55e" />
            </mesh>
         </group>

         {/* Engine */}
         <group position={[0, 0, -1.5]} ref={engineGlowRef}>
             <mesh rotation={[Math.PI/2, 0, 0]}>
                 <cylinderGeometry args={[0.3, 0.1, 0.5, 16]} />
                 <meshBasicMaterial color="#3b82f6" />
             </mesh>
             {/* Flame Core */}
             <mesh position={[0, 0, -0.8]} rotation={[Math.PI/2, 0, 0]}>
                 <coneGeometry args={[0.25, 1.5, 16]} />
                 <meshBasicMaterial color="#60a5fa" transparent opacity={0.8} blending={AdditiveBlending} depthWrite={false} />
             </mesh>
             {/* Flame Outer */}
             <mesh position={[0, 0, -0.6]} rotation={[Math.PI/2, 0, 0]}>
                 <coneGeometry args={[0.4, 1.2, 16]} />
                 <meshBasicMaterial color="#3b82f6" transparent opacity={0.4} blending={AdditiveBlending} depthWrite={false} />
             </mesh>
         </group>

         {/* Trail Effect */}
         <group position={[1.8, 0, -0.5]}>
           <Trail width={0.4} length={8} color="#00ffff" attenuation={(t) => t * t}>
              <mesh visible={false}><boxGeometry args={[0.1, 0.1, 0.1]} /></mesh>
           </Trail>
         </group>
         <group position={[-1.8, 0, -0.5]}>
           <Trail width={0.4} length={8} color="#00ffff" attenuation={(t) => t * t}>
              <mesh visible={false}><boxGeometry args={[0.1, 0.1, 0.1]} /></mesh>
           </Trail>
         </group>

      </group>
    </group>
  );
};

import React from 'react';
import { PlanetData } from '../types';

interface UIOverlayProps {
  selectedPlanet: PlanetData | null;
  onClose: () => void;
  isPaused: boolean;
  togglePause: () => void;
  simulationSpeed: number;
  setSimulationSpeed: (speed: number) => void;
  isStarshipActive: boolean;
  toggleStarship: () => void;
  showPluto: boolean;
  togglePluto: () => void;
  isGestureMode: boolean;
  toggleGestureMode: () => void;
  showOrbits: boolean;
  toggleOrbits: () => void;
  // New props for Starship control
  onBoost?: (active: boolean) => void;
  onToggleCamera?: () => void;
  cameraModeLabel?: string;
}

export const UIOverlay: React.FC<UIOverlayProps> = ({ 
  selectedPlanet, 
  onClose,
  isPaused,
  togglePause,
  simulationSpeed,
  setSimulationSpeed,
  isStarshipActive,
  toggleStarship,
  showPluto,
  togglePluto,
  toggleGestureMode,
  isGestureMode,
  showOrbits,
  toggleOrbits,
  onBoost,
  onToggleCamera,
  cameraModeLabel = "TPS"
}) => {
  // Calculations for kids
  const calculateTravelTime = (planet: PlanetData) => {
    const distanceKm = planet.realDistance * 1000000;
    const lightMinutes = (planet.realDistance / 18).toFixed(1);
    const planeHours = distanceKm / 900;
    const planeYears = (planeHours / 24 / 365).toFixed(1);
    const rocketHours = distanceKm / 40000;
    const rocketDays = Math.round(rocketHours / 24);
    const rocketYears = (rocketHours / 24 / 365).toFixed(1);
    const rocketTimeDisplay = rocketDays > 365 ? `${rocketYears} 年` : `${rocketDays} 天`;
    return { lightMinutes, planeYears, rocketTimeDisplay };
  };

  const travelInfo = selectedPlanet ? calculateTravelTime(selectedPlanet) : null;
  const MOON_IDS = ['io', 'europa', 'ganymede', 'callisto', 'moon', 'titan', 'enceladus', 'mimas', 'iapetus'];
  const isMoon = selectedPlanet && MOON_IDS.includes(selectedPlanet.id);
  const showTravelTime = selectedPlanet && selectedPlanet.id !== 'earth' && selectedPlanet.id !== 'sun' && !isMoon;
  const isEarth = selectedPlanet?.id === 'earth';

  const getPlanetTheme = (planet: PlanetData) => {
    if (planet.id === 'sun') return { icon: '☀️', type: '恒星' };
    if (planet.id === 'earth') return { icon: '🌍', type: '生命家园' };
    if (planet.id === 'pluto') return { icon: '❄️', type: '矮行星' };
    if (MOON_IDS.includes(planet.id)) return { icon: '🌑', type: '卫星' };
    if (planet.realDistance < 200) return { icon: '🪨', type: '岩石系' }; 
    if (planet.hasRings) return { icon: '🪐', type: '飞行系' };
    if (planet.realDistance > 2000) return { icon: '🧊', type: '冰系' };
    return { icon: '🎈', type: '气体系' };
  };

