  showPluto: boolean;
  togglePluto: () => void;
  isGestureMode: boolean;
  toggleGestureMode: () => void;
  showOrbits: boolean;
  toggleOrbits: () => void;
  // New props for Starship control
  onBoost?: (active: boolean) => void;
  onToggleCamera?: () => void;
  cameraModeLabel?: string;
}

