            <div className="bg-slate-900/90 space-card-border rounded-3xl p-1 shadow-2xl relative overflow-hidden">
              <div className="absolute top-0 right-0 p-4 opacity-20 pointer-events-none">
                 <svg width="80" height="80" viewBox="0 0 24 24" fill="white"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-1 17.93c-3.95-.49-7-3.85-7-7.93 0-.62.08-1.21.21-1.79L9 15v1c0 1.1.9 2 2 2v1.93zm6.9-2.54c-.26-.81-1-1.39-1.9-1.39h-1v-3c0-.55-.45-1-1-1H8v-2h2c.55 0 1-.45 1-1V7h2c1.1 0 2-.9 2-2v-.41c2.93 1.19 5 4.06 5 7.41 0 2.08-.8 3.97-2.1 5.39z"/></svg>
              </div>
              <div className="bg-black/40 rounded-2xl border border-white/10 p-4 h-full flex flex-col relative overflow-hidden">
                <button onClick={onClose} className="absolute top-3 right-3 z-20 w-8 h-8 bg-red-500/80 hover:bg-red-500 rounded-full flex items-center justify-center active:scale-95 text-white font-bold backdrop-blur-sm transition-colors">✕</button>
                <div className="flex items-center gap-3 mb-4 z-10">
                   <div className={`w-14 h-14 rounded-full border-2 border-white/30 shadow-[0_0_15px_rgba(255,255,255,0.2)] bg-gradient-to-br from-indigo-500 to-purple-700 flex items-center justify-center text-3xl`}>{getPlanetTheme(selectedPlanet).icon}</div>
                   <div>
                     <div className="text-cyan-400 text-[10px] font-mono tracking-widest uppercase mb-1">New Discovery</div>
                     <h2 className="text-3xl text-white tracking-wide drop-shadow-lg" style={{ fontFamily: '"ZCOOL KuaiLe", cursive, sans-serif' }}>{selectedPlanet.name.split(' ')[0]}</h2>
                     <div className="flex gap-2 mt-1"><span className="bg-white/10 text-blue-200 px-2 py-0.5 text-[10px] font-bold rounded border border-white/20 uppercase backdrop-blur-sm">{getPlanetTheme(selectedPlanet).type}</span></div>
                   </div>
                </div>
                <div className="flex-grow overflow-y-auto pr-2 pika-scrollbar space-y-4">
                  <div className="grid grid-cols-2 gap-2">
                    <div className="bg-slate-800/50 border border-white/10 rounded-lg p-2 flex flex-col items-center"><span className="text-[10px] font-bold text-gray-400 uppercase">平均温度</span><span className="text-sm font-bold text-white">{selectedPlanet.temperature || "未知"}</span></div>
                    <div className="bg-slate-800/50 border border-white/10 rounded-lg p-2 flex flex-col items-center"><span className="text-[10px] font-bold text-gray-400 uppercase">主要成分</span><span className="text-sm font-bold text-white text-center leading-tight">{selectedPlanet.composition || "岩石/气体"}</span></div>
                  </div>
                  <div className="bg-blue-900/20 border border-blue-500/20 rounded-lg p-3 relative mt-2">
                    <div className="absolute -top-2 -left-1 bg-blue-600 text-white text-[10px] font-bold px-2 py-0.5 rounded rotate-0 shadow-lg">DATA LOG</div>
                    <p className="text-gray-200 font-medium text-sm leading-relaxed mt-2">{selectedPlanet.description}</p>
                    {selectedPlanet.funFact && (<div className="mt-3 pt-2 border-t border-white/10 border-dashed"><span className="text-yellow-400 font-bold text-xs mr-2">⚠ 趣闻:</span><span className="text-gray-300 text-xs">{selectedPlanet.funFact}</span></div>)}
                  </div>
                  {showTravelTime && travelInfo && (
                    <div className="bg-black/40 rounded-lg p-3 border border-white/10">
                       <h3 className="text-cyan-400 text-xs font-bold uppercase mb-3 flex items-center gap-1"><span className="w-1 h-3 bg-cyan-400 rounded-full"></span>旅行时间估算</h3>
                       <div className="space-y-3">
                          <div className="flex items-center gap-2"><span className="text-[10px] font-bold text-gray-400 w-12 text-right">光速</span><div className="flex-grow h-2 bg-gray-800 rounded-full overflow-hidden relative"><div className="absolute top-0 left-0 h-full bg-yellow-400 w-full animate-pulse shadow-[0_0_10px_#facc15]"></div></div><span className="text-[10px] font-mono text-yellow-400 w-16 text-right">{travelInfo.lightMinutes} 分</span></div>
                          <div className="flex items-center gap-2"><span className="text-[10px] font-bold text-gray-400 w-12 text-right">火箭</span><div className="flex-grow h-2 bg-gray-800 rounded-full overflow-hidden relative"><div className="absolute top-0 left-0 h-full bg-red-500 w-[70%]"></div></div><span className="text-[10px] font-mono text-red-400 w-16 text-right">{travelInfo.rocketTimeDisplay}</span></div>
                          <div className="flex items-center gap-2"><span className="text-[10px] font-bold text-gray-400 w-12 text-right">飞机</span><div className="flex-grow h-2 bg-gray-800 rounded-full overflow-hidden relative"><div className="absolute top-0 left-0 h-full bg-blue-500 w-[20%]"></div></div><span className="text-[10px] font-mono text-blue-400 w-16 text-right">{travelInfo.planeYears} 年</span></div>
                       </div>
                    </div>
                  )}
                  {isEarth && (<div className="bg-emerald-900/20 rounded-lg p-3 border border-emerald-500/30"><h3 className="text-emerald-400 text-xs font-bold uppercase mb-2 flex items-center">💧 生命维持系统</h3><p className="text-emerald-100 text-xs leading-relaxed">地球表面 71% 是海洋，只有 29% 是陆地。我们有厚厚的大气层，像被子一样挡住太阳的紫外线，还锁住空气和水，让我们能自由呼吸！</p></div>)}
                </div>
                <div className="h-4 flex justify-between items-center mt-2 px-1 border-t border-white/5 pt-2">
                   <div className="flex gap-1"><div className="w-1.5 h-1.5 rounded-full bg-red-500 animate-pulse"></div><div className="w-1.5 h-1.5 rounded-full bg-yellow-500 animate-pulse delay-75"></div><div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse delay-150"></div></div>
                   <div className="text-[9px] text-cyan-700 font-mono tracking-wider">SYS.VER 3.0</div>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </>
  );
};
